var e=[{id:`L2_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`뭐가 어떻게 된 거지?`,JPN:`なにがどうなってるの？`,ENG:`How's this possible?`,TWN:`怎麼會這樣？`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`분명 들리는데…… 내 예견으로 분명 두 명의 수를 미리 읽어내고 있을 텐데……`,JPN:`確かに聞こえるのに……私の予言で確かに二人の手を先読みしているはずなのに……`,ENG:`I definitely heard it... My foresight had already read all of their moves...`,TWN:`我明明有聽到……在預言中我有讀到二個人的招數……`},stage:{bg:`BLACK`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`한 수 앞도, 열 수 앞도…… 내가 파고들 빈틈이 전혀 없어.`,JPN:`一手先も、十手先も……割り込む隙が全然ない。`,ENG:`One move, or even ten moves ahead... There's no opening for me to attack.`,TWN:`但無論我預先讀到幾招……都完全沒有漏洞可以鑽。`},stage:{bg:`BLACK`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`크읏?! 이번에도?`,JPN:`くっ！？　今度も？`,ENG:`Kgh?! Again?`,TWN:`唔呃？！這次也？`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`하하…… 아하하……`,JPN:`はは……あはは……`,ENG:`Hah hah... Ah hah hah...`,TWN:`哈哈……哈哈哈……`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`아니야. 난 지지 않아.`,JPN:`違う。私は負けない。`,ENG:`No. I don't lose.`,TWN:`不會的，我不會輸。`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`난…… 너희들의 약점을 알고 있으니까!`,JPN:`私は……お前たちの弱点を知っているもの！`,ENG:`Because... I know your weaknesses!`,TWN:`因為……我知道你們的弱點！`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`빈틈이 없다면, 다른 곳에서 찾아주지!`,JPN:`隙がないなら、他のところから探し出すまでよ！`,ENG:`If there is no opening, then I'll make one myself!`,TWN:`這裡沒有破綻，我就從別的地方找！`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`사라졌어?`,JPN:`消えた？`,ENG:`Where did she go?`,TWN:`消失了？`},stage:{bg:`NANAHARA_SEAL`,slots:{L:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`SANAE_NANA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L18_1`,type:`dialog`,speaker:`SANAE_NANA_NULL_NULL`,text:{KOREA:`광학위장기술입니다. 기척마저 감췄군요.`,JPN:`光学迷彩ですね。気配まで消えました。`,ENG:`It is optical camouflage technology. She has even erased her presence.`,TWN:`是光學偽裝技術，連動靜都可以隱藏。`},stage:{bg:`NANAHARA_SEAL`,slots:{L:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`SANAE_NANA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L19_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`약점이라면……`,JPN:`弱点といえば……`,ENG:`The weakness she is looking for...`,TWN:`她說弱點……`},stage:{bg:`NANAHARA_SEAL`,slots:{L:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`SANAE_NANA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L20_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`……설마 당주님을?!`,JPN:`……まさか当主を！？`,ENG:`...Could she have been talking about Lady Nanahara?!`,TWN:`……難道是指堂主？！`},stage:{bg:`NANAHARA_SEAL`,slots:{L:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`SANAE_NANA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L21_1`,type:`dialog`,speaker:`SANAE_NANA_NULL_NULL`,text:{KOREA:`치후유님?`,JPN:`千冬様？`,ENG:`Miss Chifuyu?`,TWN:`千冬？`},stage:{bg:`NANAHARA_SEAL`,slots:{L:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`SANAE_NANA_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L22_1`,type:`dialog`,speaker:`SANAE_NANA_NULL_NULL`,text:{KOREA:`안 됩니다. 여기서 흐트러지면……!`,JPN:`いけません。ここで乱れてしまっては……！`,ENG:`Stay calm. If you lose focus now...!`,TWN:`不可以，要是我們分散……！`},stage:{bg:`NANAHARA_SEAL`,slots:{L:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`SANAE_NANA_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L24_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`……당주님!`,JPN:`……当主！`,ENG:`...Lady Nanahara!`,TWN:`……堂主！`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}}];export{e as default};